import React, { useState } from "react";
import axios from "axios";
import { WiDaySunny, WiHumidity, WiStrongWind } from "react-icons/wi";
import { motion } from "framer-motion";

const weatherImages = {
    Clear: "https://cdn-icons-png.flaticon.com/512/869/869869.png",  // Sunny
    Clouds: "https://cdn-icons-png.flaticon.com/512/414/414825.png", // Cloudy
    Rain: "https://cdn-icons-png.flaticon.com/512/1163/1163657.png", // Rainy
    Thunderstorm: "https://cdn-icons-png.flaticon.com/512/3075/3075858.png", // Thunderstorm
    Snow: "https://cdn-icons-png.flaticon.com/512/2315/2315309.png", // Snowy
    Mist: "https://cdn-icons-png.flaticon.com/512/1779/1779809.png", // Mist
    Wind: "https://cdn-icons-png.flaticon.com/512/848/848043.png", // Wind speed
};

const WeatherUpdate = () => {
    const [city, setCity] = useState("");
    const [weather, setWeather] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchWeather = async () => {
        if (!city) {
            setError("Please enter a city name.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.get(`http://localhost:5000/api/weather/getWeather?city=${city}`);
            setWeather(response.data);
        } catch (err) {
            setError("Failed to fetch weather data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ maxWidth: "400px", margin: "auto", padding: "20px", textAlign: "center", border: "1px solid #ddd", borderRadius: "15px", backgroundColor: "#f0f8ff" }}>
            <h2>🌤 Weather Update</h2>
            <input
                type="text"
                placeholder="Enter city name"
                value={city}
                onChange={(e) => setCity(e.target.value)}
                style={{ padding: "10px", width: "80%", marginBottom: "10px", borderRadius: "5px", border: "1px solid #ccc" }}
            />
            <br />
            <button 
                onClick={fetchWeather} 
                style={{ padding: "10px 20px", border: "none", backgroundColor: "#007bff", color: "white", borderRadius: "5px", cursor: "pointer" }}
            >
                Get Weather
            </button>

            {loading && <p>Loading...</p>}
            {error && <p style={{ color: "red" }}>{error}</p>}

            {weather && (
                <motion.div 
                    initial={{ opacity: 0, y: -20 }} 
                    animate={{ opacity: 1, y: 0 }} 
                    transition={{ duration: 0.5 }}
                    style={{ marginTop: "20px", padding: "10px", background: "#f8f9fa", borderRadius: "5px" }}
                >
                    <h3>{weather.location}</h3>
                    
                    {/* Display Weather Condition Image */}
                    {weather.condition && (
                        <img 
                            src={weatherImages[weather.condition] || weatherImages["Clear"]} 
                            alt={weather.condition} 
                            style={{ width: "80px", height: "80px", marginBottom: "10px" }}
                        />
                    )}

                    <p><WiDaySunny /> Temperature: {weather.temperature}°C</p>
                    <p><WiHumidity /> Humidity: {weather.humidity}%</p>

                    {/* Wind Speed Image */}
                    <p>
                        <img 
                            src={weatherImages["Wind"]} 
                            alt="Wind Speed" 
                            style={{ width: "30px", height: "30px", verticalAlign: "middle" }}
                        /> 
                        Wind Speed: {weather.wind_speed} m/s
                    </p>
                </motion.div>
            )}
        </div>
    );
};

export default WeatherUpdate;
